It happened that I came to use the _smt_ tactic at the end of my strategy chain. I also found **Z3_tactic_par_or** tactic combinator very fortunate, since the previous troubled strategy happened to actually deliver pretty well in cases when bitvector extraction enablers just cancelled out early on during simplifications. So, after all, I decided to use this structure (below), and I have no idea how could this possibly be automatically decided within z3; rather than just falling back to the most general solver of all:

```
inline z3::tactic mk_tactics(z3::context& ctx, SolverConfig* config){
		z3::tactic tact = z3::tactic(ctx, "simplify");
		z3::params tp0(ctx);
		tp0.set("push_ite_bv", true);
		tp0.set("push_ite_arith", true);
		tp0.set("cache-all", true);
		z3::params elim_and(ctx);
		z3::tactic qfaufbv(ctx, "qfaufbv");
		z3::tactic solve_eqs(ctx, "solve-eqs");
		z3::tactic simplify(ctx, "simplify");
		z3::tactic bit_blast(ctx, "bit-blast");
		z3::tactic tseitin_cnf(ctx, "tseitin-cnf");
		z3::tactic sat(ctx, "sat");
		z3::tactic aig(ctx, "aig");
		z3::tactic smt(ctx, "smt");
		z3::tactic fpa2bv(ctx, "fpa2bv");
		z3::tactic bvarray2uf(ctx, "bvarray2uf");
		z3::tactic ackermannize_bv(ctx, "ackermannize_bv");
		elim_and.set("elim_and", true);
		Z3_tactic ts[6];
		z3::tactic t0 = simplify;
		z3::tactic t1 = simplify;
		z3::tactic t2 = simplify;
		z3::tactic t3 = simplify;
		z3::tactic t4 = simplify;
		z3::tactic t5 = simplify;
		
                t0 = t0 & ackermannize_bv & with(qfaufbv, tp0) & with(simplify, elim_and) & bit_blast & sat & smt;
		if (config->setGaussianEliminationTactic) t1 = t1 & solve_eqs;
		if (config->setBitBlastTactic) t1 = t1 & bit_blast;
		if (config->setCNFConversionTactic) t1 = t1 & tseitin_cnf;
		if (true) t1 = t1 & sat;
		if (true) t1 = t1 & smt;
		if (config->setBitBlastTactic) t2 = t2 & bit_blast;
		if (config->setCNFConversionTactic) t2 = t2 & tseitin_cnf;
		if (true) t2 = t2 & sat;
		if (true) t2 = t2 & smt;
		if (config->setGaussianEliminationTactic) t3 = t3 & solve_eqs;
		if (config->setBitBlastTactic) t3 = t3 & bit_blast;
		if (config->setCNFConversionTactic) t3 = t3 & tseitin_cnf;
		if (true) t3 = t3 & aig;
		if (true) t3 = t3 & sat;
		if (true) t3 = t3 & smt;
		if (config->setBitBlastTactic) t4 = t4 & bit_blast;
		if (config->setCNFConversionTactic) t4 = t4 & tseitin_cnf;
		if (true) t4 = t4 & aig;
		if (true) t4 = t4 & sat;
		if (true) t4 = t4 & smt;
		t5 = t5 & fpa2bv & bvarray2uf & ackermannize_bv & qfaufbv & with(simplify, elim_and) & bit_blast & sat & smt;
		ts[0] = t0.operator _Z3_tactic *();
		ts[1] = t1.operator _Z3_tactic *();
		ts[2] = t2.operator _Z3_tactic *();
		ts[3] = t3.operator _Z3_tactic *();
		ts[4] = t4.operator _Z3_tactic *();
		ts[5] = t5.operator _Z3_tactic *();
		tact = tact & z3::tactic(ctx, Z3_tactic_par_or(ctx, 6, ts));
		return tact;
	}
```

